+
+    #[test]
+    fn reset_clears_state() {
+        let mut ext = BreathingExtractor::new(2, 10.0, 30.0);
+        ext.extract(&[1.0, 2.0], &[0.5, 0.5]);
+        assert!(ext.history_len() > 0);
