+    #[test]
+    fn bssid_id_roundtrip() {
+        let mac = [0xaa, 0xbb, 0xcc, 0xdd, 0xee, 0xff];
+        let id = BssidId(mac);
+        assert_eq!(id.to_string(), "aa:bb:cc:dd:ee:ff");
+        assert_eq!(BssidId::parse("aa:bb:cc:dd:ee:ff").unwrap(), id);
+    }
